logger = logging.getLogger(__name__)

_STATE_PRIORITY = {
    StatusState.PERMISSION_REQUIRED: 0,
    StatusState.AWAITING_INPUT: 1,
    StatusState.WORKING: 2,
    StatusState.READY: 3,
    StatusState.IDLE: 4,
}

# States where the user can take an action (approve, answer, navigate, etc.)
_ACTIONABLE_STATES = frozenset(
    {
        StatusState.PERMISSION_REQUIRED,
        StatusState.AWAITING_INPUT,
        StatusState.READY,
        StatusState.IDLE,
    }
)

_DEBOUNCE_MS = 300  # Debounce window for state display updates (FR-043)


def read_daily_cost() -> float:
    """Sum today's session costs from the session tracker."""
    today = datetime.date.today().isoformat()
    today_dir = config.SESSION_TRACKER_DIR / today
    if not today_dir.is_dir():
        return 0.0
    total = 0.0
    for path in today_dir.glob("*.json"):
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
            total += data.get("cost", {}).get("total_cost_usd", 0) or 0
        except (json.JSONDecodeError, OSError):
            continue
    return total


def read_usage_limits() -> dict:
    """Read cached OAuth usage limits. Returns empty dict if unavailable."""
    if not config.OAUTH_USAGE_CACHE.exists():
        return {}
    try:
        data = json.loads(config.OAUTH_USAGE_CACHE.read_text(encoding="utf-8"))
        if isinstance(data, dict):
            return data
    except (json.JSONDecodeError, OSError):
        pass
    return {}


