        self._daily_cost_last_read: float = 0.0
        self._usage_limits: dict = {}

        # PID -> _SessionEntry
        self._sessions: dict[int, _SessionEntry] = {}
        # session_id -> PID (reverse lookup for hook events)
        self._session_id_to_pid: dict[str, int] = {}
        # Buffer for hook events arriving before session discovery
